/**
 * Seed script — migrates all live content from the public site into Supabase.
 * Run with: node scripts/seed-content.mjs
 */

import { readFileSync } from "fs";
import { join, dirname } from "path";
import { fileURLToPath } from "url";
import postgres from "postgres";

const __dirname = dirname(fileURLToPath(import.meta.url));

// ─── Load .env.local ─────────────────────────────────────────────────────────
function loadEnv() {
  try {
    const raw = readFileSync(join(__dirname, "../.env.local"), "utf8");
    for (const line of raw.split("\n")) {
      const m = line.match(/^([A-Z0-9_]+)="?([^"]*)"?/);
      if (m) process.env[m[1]] = m[2];
    }
  } catch {}
}
loadEnv();

const DATABASE_URL = process.env.DATABASE_URL;
if (!DATABASE_URL) {
  console.error("DATABASE_URL not found in .env.local");
  process.exit(1);
}

const sql = postgres(DATABASE_URL, { ssl: "require", max: 3 });

// ─── ADD MISSING COLUMNS ─────────────────────────────────────────────────────
async function ensureColumns() {
  await sql`
    ALTER TABLE destinations
      ADD COLUMN IF NOT EXISTS tagline VARCHAR(255),
      ADD COLUMN IF NOT EXISTS highlights JSONB DEFAULT '[]'::jsonb,
      ADD COLUMN IF NOT EXISTS coords VARCHAR(100)
  `;
  console.log("✓ destinations schema up-to-date");
}

