// ─── SEED FUNCTIONS ───────────────────────────────────────────────────────────
async function seedTours() {
  let count = 0;
  for (const t of tours) {
    await sql`
      INSERT INTO tours (id, title, subtitle, description, days, from_city, to_city, price, image, itinerary, included, highlights, status, featured, sort_order)
      VALUES (
        ${t.id}, ${t.title}, ${t.subtitle}, ${t.description}, ${t.days},
        ${t.from_city}, ${t.to_city}, ${t.price}, ${t.image},
        ${JSON.stringify(t.itinerary)}, ${JSON.stringify(t.included)}, ${JSON.stringify(t.highlights)},
        ${t.status}, ${t.featured}, ${t.sort_order}
      )
      ON CONFLICT (id) DO UPDATE SET
        title = EXCLUDED.title, subtitle = EXCLUDED.subtitle, description = EXCLUDED.description,
        days = EXCLUDED.days, from_city = EXCLUDED.from_city, to_city = EXCLUDED.to_city,
        price = EXCLUDED.price, image = EXCLUDED.image, itinerary = EXCLUDED.itinerary,
        included = EXCLUDED.included, highlights = EXCLUDED.highlights,
        status = EXCLUDED.status, featured = EXCLUDED.featured, sort_order = EXCLUDED.sort_order
    `;
    count++;
  }
  console.log(`✓ tours: ${count} upserted`);
}

