async function seedTestimonials() {
  await sql`DELETE FROM testimonials`;
  let count = 0;
  for (const t of testimonials) {
    await sql`
      INSERT INTO testimonials (name, location, text, rating, image, tour_id, featured)
      VALUES (${t.name}, ${t.location}, ${t.text}, ${t.rating}, ${t.image}, ${t.tour_id}, ${t.featured})
    `;
    count++;
  }
  console.log(`✓ testimonials: ${count} inserted`);
}

// ─── MAIN ─────────────────────────────────────────────────────────────────────
async function main() {
  console.log("Starting content seed...\n");
  try {
    await ensureColumns();
    await seedTours();
    await seedBlogPosts();
    await seedDestinations();
    await seedTestimonials();
    console.log("\nSeed complete!");
  } catch (err) {
    console.error("Seed failed:", err.message);
    process.exit(1);
  } finally {
    await sql.end();
  }
}

main();
